func playUntilSave(w *World, steps []ScriptStep, profile Profile, radius int) (a0.ItemY, map[string]bool) {
        visStale := map[string]bool{}
        var blob a0.ItemY
        for _, step := range steps {
                w.Turn = step.Turn
